const t={configEditor:{intro:{t:0,b:{t:2,i:[{t:3}],s:"اقرأ التهيئة الحيّة لطابعتك مباشرةً من Moonraker — كل ملف، محلَّلًا إلى أقسام وبارامترات، مع الإشارة إلى المشكلات البنيوية. للقراءة فقط حاليًا؛ التحرير الموجَّه قادم لاحقًا."}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"مساعدة"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"حول محرّر التهيئة"}},close:{t:0,b:{t:2,i:[{t:3}],s:"إغلاق"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"كيفية الاستخدام"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"اختر ملف تهيئة من القائمة المنسدلة — يُحدَّد printer.cfg افتراضيًا."}},{t:0,b:{t:2,i:[{t:3}],s:"تصفّح أقسامه؛ انقر على قسم لتوسيع بارامتراته."}},{t:0,b:{t:2,i:[{t:3}],s:"تحقّق من لافتة التحقّق بحثًا عن مشكلات بنيوية مثل قسم مكرَّر."}},{t:0,b:{t:2,i:[{t:3}],s:"بدّل إلى العرض الخام لقراءة نص الملف بالضبط."}}],topics:{sections:{title:{t:0,b:{t:2,i:[{t:3}],s:"الأقسام والبارامترات"}},body:{t:0,b:{t:2,i:[{t:3}],s:"تهيئة Klipper عبارة عن قائمة من كتل [section]، تحمل كل منها بارامترات بصيغة key: value. يحلّل هذا العنصر كل قسم — بما في ذلك ما له اسم مثل [tmc2209 stepper_x] — ويسرد بارامتراته مع قيمتها وأي تعليق سطري. تُحفَظ القيم متعدّدة الأسطر (مثل gcode: في ماكرو) كما هي."}}},includes:{title:{t:0,b:{t:2,i:[{t:3}],s:"الملفات المضمَّنة"}},body:{t:0,b:{t:2,i:[{t:3}],s:"غالبًا ما يستدعي printer.cfg ملفات أخرى عبر [include other.cfg] (أو نمط شامل مثل [include configs/*.cfg]). يُعرَض كل تضمين كإدخال مستقل؛ اختر الملف المضمَّن من القائمة المنسدلة لفحص ما يعرّفه."}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"التحقّق"}},body:{t:0,b:{t:2,i:[{t:3}],s:"بعد التحليل، تُفحَص التهيئة بحثًا عن مشكلات بنيوية خاطئة بصرف النظر عن نوع القسم — رأس قسم مكرَّر، أو اسم قسم فارغ، أو بارامتر خارج أي قسم. تظهر هذه في لافتة التحقّق؛ وهي لا تغيّر ملفك."}}},saveConfig:{title:{t:0,b:{t:2,i:[{t:3}],s:"كتلة SAVE_CONFIG"}},body:{t:0,b:{t:2,i:[{t:3}],s:"يُلحِق Klipper كتلة مُولَّدة تلقائيًا في نهاية printer.cfg (بعد علامة #*#) عند تشغيل SAVE_CONFIG — نتائج المعايرة مثل قيم PID وإزاحات Z. تُعرَض هذه الكتلة لكن يُشار إليها كمحفوظة تلقائيًا، وتُستبعَد من عدد الأقسام القابلة للتحرير لأنه لا ينبغي تحريرها يدويًا."}}},readonly:{title:{t:0,b:{t:2,i:[{t:3}],s:"للقراءة فقط (حاليًا)"}},body:{t:0,b:{t:2,i:[{t:3}],s:"هذا الإصدار الأول يقرأ التهيئة ويعرضها فقط — لا يُكتَب شيء إلى الطابعة. التحرير الموجَّه المحمي بالتأكيد (مع نسخة احتياطية تلقائية قبل أي حفظ وإعادة تشغيل بعده) سيصل في تحديث لاحق."}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"المسرد"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{section:{term:{t:0,b:{t:2,i:[{t:3}],s:"القسم"}},def:{t:0,b:{t:2,i:[{t:3}],s:"كتلة [header] تجمّع إعدادات مترابطة، مثل [stepper_x] أو [extruder]."}}},parameter:{term:{t:0,b:{t:2,i:[{t:3}],s:"البارامتر"}},def:{t:0,b:{t:2,i:[{t:3}],s:"سطر بصيغة key: value (أو key = value) داخل قسم، مع تعليق # في النهاية اختياريًا."}}},include:{term:{t:0,b:{t:2,i:[{t:3}],s:"[include]"}},def:{t:0,b:{t:2,i:[{t:3}],s:"توجيه يستدعي ملف تهيئة آخر إلى داخل printer.cfg، بحيث يمكن تقسيم الإعدادات عبر عدّة ملفات."}}},saveConfig:{term:{t:0,b:{t:2,i:[{t:3}],s:"SAVE_CONFIG"}},def:{t:0,b:{t:2,i:[{t:3}],s:"الكتلة المُولَّدة تلقائيًا (بعد #*#) حيث يخزّن Klipper نتائج المعايرة — لا تحرّرها يدويًا."}}}}},file:{label:{t:0,b:{t:2,i:[{t:3}],s:"ملف التهيئة"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"اختر ملفًا…"}},refresh:{t:0,b:{t:2,i:[{t:3}],s:"تحديث"}},loadingList:{t:0,b:{t:2,i:[{t:3}],s:"جارٍ تحميل الملفات…"}},emptyList:{t:0,b:{t:2,i:[{t:3}],s:"لم يُعثَر على ملفات تهيئة على الطابعة."}}},summary:{sections:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" أقسام"}]}},params:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" بارامترات"}]}},size:{t:0,b:{t:2,i:[{t:4,k:"kb"},{t:3,v:" KB"}]}}},validation:{title:{t:0,b:{t:2,i:[{t:3}],s:"التحقّق"}},clean:{t:0,b:{t:2,i:[{t:3}],s:"لم يُعثَر على مشكلات بنيوية."}},error:{t:0,b:{t:2,i:[{t:3}],s:"خطأ"}},warning:{t:0,b:{t:2,i:[{t:3}],s:"تحذير"}}},view:{structured:{t:0,b:{t:2,i:[{t:3}],s:"منظَّم"}},raw:{t:0,b:{t:2,i:[{t:3}],s:"خام"}},expandAll:{t:0,b:{t:2,i:[{t:3}],s:"توسيع الكل"}},collapseAll:{t:0,b:{t:2,i:[{t:3}],s:"طيّ الكل"}}},section:{saveBadge:{t:0,b:{t:2,i:[{t:3}],s:"محفوظ تلقائيًا"}},noParams:{t:0,b:{t:2,i:[{t:3}],s:"(لا توجد بارامترات)"}},paramsCount:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" بارامترات"}]}},paramHead:{t:0,b:{t:2,i:[{t:3}],s:"البارامتر"}},valueHead:{t:0,b:{t:2,i:[{t:3}],s:"القيمة"}}},states:{loading:{t:0,b:{t:2,i:[{t:3}],s:"جارٍ قراءة التهيئة…"}},error:{t:0,b:{t:2,i:[{t:3}],s:"تعذّرت قراءة التهيئة من الطابعة."}},retry:{t:0,b:{t:2,i:[{t:3}],s:"إعادة المحاولة"}}}}};export{t as default};
